class TestConnectionManager:
    async def test_broadcast_sends_to_all(self) -> None:
        mgr = ConnectionManager()
        ws1 = AsyncMock()
        ws2 = AsyncMock()
        mgr._connections = [ws1, ws2]

        await mgr.broadcast({"test": True})

        ws1.send_text.assert_called_once()
        ws2.send_text.assert_called_once()
        payload = json.loads(ws1.send_text.call_args[0][0])
        assert payload == {"test": True}

    async def test_broadcast_removes_dead_connections(self) -> None:
        mgr = ConnectionManager()
        ws_alive = AsyncMock()
        ws_dead = AsyncMock()
        ws_dead.send_text.side_effect = RuntimeError("disconnected")
        mgr._connections = [ws_alive, ws_dead]

        await mgr.broadcast({"test": True})

        assert mgr.connection_count == 1
        assert ws_alive in mgr._connections

    def test_disconnect_removes(self) -> None:
        mgr = ConnectionManager()
        ws = MagicMock()
        mgr._connections = [ws]
        mgr.disconnect(ws)
        assert mgr.connection_count == 0

    def test_disconnect_not_present(self) -> None:
        mgr = ConnectionManager()
        ws = MagicMock()
        mgr.disconnect(ws)  # Should not raise


class TestWebSocketEndpoint:
    def test_websocket_connect_and_receive(self, db) -> None:
        app = FastAPI()
        app.include_router(ws_router)
        app.include_router(hooks_router)

        client = TestClient(app)
        with client.websocket_connect("/ws") as ws:
            # Send a hook event — the WS should receive the broadcast
            client.post(
                "/hooks/claude",
                json={
                    "session_id": "s1",
                    "hook_event_name": "PreToolUse",
                    "tool_name": "Bash",
                },
            )
            # First message is session_discovered (new session)
            data = ws.receive_json()
            assert data["type"] == "session_discovered"
            assert data["session_id"] == "s1"

            # Second message is the hook_event itself
            data = ws.receive_json()
            assert data["type"] == "hook_event"
            assert data["session_id"] == "s1"
            assert data["tool_name"] == "Bash"
